import Foundation
import Combine
import FactoryKit

@Observable
final class BluetoothDevice {

    @ObservationIgnored
    @Injected(\.settingComposer) private var settingComposer

    enum BluetoothDeviceError: Error {
        case transmition
    }

    // MARK: Private properties
    @ObservationIgnored
    private var transmition: DeviceTransmition?

    @ObservationIgnored
    private var cancellables = Set<AnyCancellable>()

    // MARK: Properties

    /// Устройство
    let radiacode: RadiaCode.Device

    /// Объект для взаимодействия с блютуз протоколом
    let peripheral: Peripheral?

    /// Состояние устройства
    var state: PeripheralImpl.ConnectionState = .disconnected
    /// RSSI
    var signal: BluetoothSignal

    /// Настройки
    var settings: Settings
    /// Прошивка
    var firmware: Firmware
    /// Пороговые значения тревог
    var alarms: Alarm
    /// Настройки спектра
    var spectrumSettings: SpectrumSettings
    /// Настройки устройства
    var configurationSettings: ConfigurationSettings = .default
    /// Базовое установленное прибором время (timeIntervalSince1970)
    var deviceBaseDate: Double = 0.0

    init(
        radiacode: RadiaCode.Device,
        signal: BluetoothSignal,
        peripheral: Peripheral?
    ) {
        self.radiacode = radiacode
        self.signal = signal
        self.peripheral = peripheral

        self.settings = .init()
        self.firmware = .init()
        self.alarms = .init()
        self.spectrumSettings = .init()

        self.setupObservers()
    }

    @discardableResult
    func send<T: BluetoothCommand>(command: T) async -> Result<T.Response, Error> {
        guard let transmition else {
            return .failure(BluetoothDeviceError.transmition)
        }
        return await transmition.send(command: command)
    }

    func start() async {
        transmition = DeviceTransmition(peripheral: self.peripheral)
        await setupSettingsObserver()
    }

    func reset() async {
        cancellables.removeAll()
        await stopCommands()
    }

    func stopCommands() async {
        await transmition?.stop()
        transmition = nil
    }

    deinit {
        Log.debug("BluetoothDevice Removed \(identifier)")
    }
}

// MARK: - Configuration
private extension BluetoothDevice {

    func setupObservers() {
        peripheral?.connectionState
            .removeDuplicates()
            .dropFirst()
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self = self else { return }
                self.state = state
                Log.debug("\(self.identifier) STATE: \(state)")
            }
            .store(in: &cancellables)

        peripheral?.bluetoothSignal
            .removeDuplicates()
            .receive(on: DispatchQueue.main)
            .sink { [weak self] signal in
                self?.signal = signal
            }
            .store(in: &cancellables)
    }

    func setupSettingsObserver() async {
        await settingComposer.settingsChangedSubject
            .sink { [weak self] settingComposer in
                guard let self = self else { return }
                Task { @MainActor in
                    self.settings.vibration = await settingComposer
                        .isEnabled(setting: .device(.vibration))

                    self.settings.clickers = await settingComposer
                        .isEnabled(setting: .sound(.clickers))

                    self.settings.sound = await settingComposer
                        .isEnabled(setting: .device(.sound))

                    self.settings.leds = await settingComposer
                        .isEnabled(setting: .device(.leds))

                    self.settings.power = await settingComposer
                        .isEnabled(setting: .device(.power))

                    let soundAlarm = await settingComposer.isEnabled(setting: .sound(.alarm))
                    let vibroAlarm = await settingComposer.isEnabled(setting: .vibro(.alarm))
                    self.settings.alarm = soundAlarm || vibroAlarm
                }
            }
            .store(in: &cancellables)
    }
}

extension BluetoothDevice {

    @Observable
    final class Settings {
        var vibration = false
        var clickers = false
        var sound = false
        var leds = false
        var alarm = false
        var power = false
        var temperatureUnit: TemperatureUnit = .celsius
    }
}

extension BluetoothDevice: Equatable {

    static func == (lhs: BluetoothDevice, rhs: BluetoothDevice) -> Bool {
        lhs.radiacode == rhs.radiacode
    }

    static let mock = BluetoothDevice(
        radiacode: .mock,
        signal: .strong,
        peripheral: nil
    )
}

