        settingsChangedSubscription = nil
        await stopCommands()
    }

    func stopCommands() async {
        await transmition?.stop()
        transmition = nil
    }

    deinit {
        Log.debug("BluetoothDevice Removed \(identifier)")
    }
}

// MARK: - Configuration
private extension BluetoothDevice {

    func setupObservers() {
        connectionStateSubscription = peripheral?.connectionState
            .removeDuplicates()
            .dropFirst()
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self = self else { return }
                self.state = state
                Log.debug("\(self.identifier) STATE: \(state)")
            }

        bluetoothSignalSubscription = peripheral?.bluetoothSignal
            .removeDuplicates()
            .receive(on: DispatchQueue.main)
            .sink { [weak self] signal in
                self?.signal = signal
            }
    }

    func setupSettingsObserver() async {
        await settingComposer.settingsChangedSubject
            .sink { [weak self] settingComposer in
                guard let self = self else { return }
                Task { @MainActor in
                    self.settings.vibration = await settingComposer
                        .isEnabled(setting: .device(.vibration))

                    self.settings.clickers = await settingComposer
                        .isEnabled(setting: .sound(.clickers))

                    self.settings.sound = await settingComposer
                        .isEnabled(setting: .device(.sound))

                    self.settings.leds = await settingComposer
                        .isEnabled(setting: .device(.leds))

                    self.settings.power = await settingComposer
                        .isEnabled(setting: .device(.power))

                    let soundAlarm = await settingComposer.isEnabled(setting: .sound(.alarm))
                    let vibroAlarm = await settingComposer.isEnabled(setting: .vibro(.alarm))
                    self.settings.alarm = soundAlarm || vibroAlarm
                }
            }
            .store(in: &cancellables)
    }
}

extension BluetoothDevice {

    @Observable
    final class Settings {
        var vibration = false
        var clickers = false
        var sound = false
        var leds = false
        var alarm = false
        var power = false
        var temperatureUnit: TemperatureUnit = .celsius
    }
}

extension BluetoothDevice: Equatable {

    static func == (lhs: BluetoothDevice, rhs: BluetoothDevice) -> Bool {
        lhs.radiacode == rhs.radiacode
    }

    static let mock = BluetoothDevice(
        radiacode: .mock,
        signal: .strong,
        peripheral: nil
    )
}

