grep "^Bash|" /tmp/calls.txt | sed 's/^Bash|//' | awk '{
  # Strip env-var prefixes, leading sudo/timeout
  cmd=$0
  sub(/^[A-Z_]+=[^ ]+ +/, "", cmd)
  sub(/^sudo +/, "", cmd)
  sub(/^timeout +[0-9smh]+ +/, "", cmd)
  # Take first segment before pipe/&&/;
  split(cmd, a, /[\|&;]/)
  c=a[1]
  # First two tokens
  n=split(c, t, / +/)
  first=t[1]; second=t[2]
  if (first=="git" || first=="gh" || first=="docker" || first=="kubectl" || first=="bun" || first=="npm" || first=="yarn" || first=="pnpm" || first=="cargo" || first=="go" || first=="make") {
    print first " " second
  } else {
    print first
  }
}' | sort | uniq -c | sort -rn | head -40
